INSERT INTO `chamado_templates` (`id`, `titulo`, `corpo`, `ordem`, `criado_em`) VALUES
(6, 'Abertura — Recebemos seu chamado', 'Olá {{cliente}},\n\nRecebemos seu chamado e já estamos analisando. Em breve retornaremos com mais informações.\n\nAtenciosamente,\n{{responsavel}}', 1, '2026-04-27 16:38:06'),
(7, 'Em andamento', 'Olá {{cliente}},\n\nEstamos trabalhando na resolução do seu chamado. Assim que houver atualizações, enviaremos por aqui.\n\nAtenciosamente,\n{{responsavel}}', 2, '2026-04-27 16:38:06'),
(8, 'Solicitar mais informações', 'Olá {{cliente}},\n\nPara dar andamento ao seu chamado, precisamos de algumas informações adicionais:\n\n- \n- \n\nAssim que possível, nos envie.\n\nAtenciosamente,\n{{responsavel}}', 3, '2026-04-27 16:38:06'),
(9, 'Aguardando retorno', 'Olá {{cliente}},\n\nEnviamos uma solicitação e ainda aguardamos sua resposta. Poderia nos dar um retorno?\n\nAtenciosamente,\n{{responsavel}}', 4, '2026-04-27 16:38:06'),
(10, 'Resolvido', 'Olá {{cliente}},\n\nSeu chamado foi resolvido. Qualquer dúvida, basta responder esta mensagem ou abrir um novo chamado.\n\nAtenciosamente,\n{{responsavel}}', 5, '2026-04-27 16:38:06');
